steps.script:
var sc = tree.current_scene.shooting_controller
for i in range(sc._pad_cycle_ring().size()):
	var ok_weapon = false
	if sc.weapon_tree != null and sc.weapon_tree.get_root() != null:
		var it = sc.weapon_tree.get_root().get_first_child()
		while it != null:
			if it.is_selectable(0):
				ok_weapon = true
				break
			it = it.get_next()
	if ok_weapon and not sc.eligible_targets.is_empty():
		break
	sc._keyboard_cycle_units(false)
InputDeviceManager.set_meta("shooter", str(sc.active_shooter_id))
return not sc.eligible_targets.is_empty()
